import{_ as i,o as n,c as a,ai as h}from"./chunks/framework.CJDL-GS7.js";const g=JSON.parse('{"title":"Thi trực tuyến","description":"","frontmatter":{},"headers":[],"relativePath":"exam-guide.md","filePath":"exam-guide.md","lastUpdated":null}'),o={name:"exam-guide.md"};function r(e,t,l,c,u,s){return n(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="thi-truc-tuyen" tabindex="-1">Thi trực tuyến <a class="header-anchor" href="#thi-truc-tuyen" aria-label="Permalink to &quot;Thi trực tuyến&quot;">​</a></h1><p>Bài kiểm tra trên TunAcademy được thực hiện hoàn toàn trực tuyến với giới hạn thời gian. Kết quả và đáp án được công bố ngay sau khi nộp bài.</p><h2 id="xem-danh-sach-bai-kiem-tra" tabindex="-1">Xem danh sách bài kiểm tra <a class="header-anchor" href="#xem-danh-sach-bai-kiem-tra" aria-label="Permalink to &quot;Xem danh sách bài kiểm tra&quot;">​</a></h2><ol><li>Vào <strong>Bài kiểm tra</strong> trên sidebar</li><li>Danh sách các đề thi theo từng lớp</li></ol><h3 id="trang-thai-đe-thi" tabindex="-1">Trạng thái đề thi <a class="header-anchor" href="#trang-thai-đe-thi" aria-label="Permalink to &quot;Trạng thái đề thi&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trạng thái</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>🟡 <strong>Chưa làm</strong></td><td>Đề thi đang mở, bạn chưa thi</td></tr><tr><td>🟢 <strong>Đã hoàn thành</strong></td><td>Đã nộp bài, có kết quả</td></tr><tr><td>🔴 <strong>Hết hạn</strong></td><td>Đã qua thời gian cho phép thi</td></tr><tr><td>🔒 <strong>Chưa mở</strong></td><td>Giáo viên chưa kích hoạt đề thi</td></tr></tbody></table><h2 id="quy-trinh-thi" tabindex="-1">Quy trình thi <a class="header-anchor" href="#quy-trinh-thi" aria-label="Permalink to &quot;Quy trình thi&quot;">​</a></h2><h3 id="buoc-1-—-chuan-bi" tabindex="-1">Bước 1 — Chuẩn bị <a class="header-anchor" href="#buoc-1-—-chuan-bi" aria-label="Permalink to &quot;Bước 1 — Chuẩn bị&quot;">​</a></h3><p>Trước khi bắt đầu:</p><ul><li>Đảm bảo kết nối internet ổn định</li><li>Đọc kỹ <strong>thông tin đề thi</strong>: số câu, thời gian, cách tính điểm</li><li>Không mở tab khác trong lúc thi</li></ul><h3 id="buoc-2-—-vao-phong-thi" tabindex="-1">Bước 2 — Vào phòng thi <a class="header-anchor" href="#buoc-2-—-vao-phong-thi" aria-label="Permalink to &quot;Bước 2 — Vào phòng thi&quot;">​</a></h3><ol><li>Nhấn vào đề thi → nhấn <strong>Bắt đầu làm bài</strong></li><li>Đồng hồ đếm ngược bắt đầu chạy ngay lập tức</li><li>Không thể tạm dừng khi đã bắt đầu</li></ol><h3 id="buoc-3-—-lam-bai" tabindex="-1">Bước 3 — Làm bài <a class="header-anchor" href="#buoc-3-—-lam-bai" aria-label="Permalink to &quot;Bước 3 — Làm bài&quot;">​</a></h3><ul><li>Câu hỏi hiển thị từng câu hoặc toàn bộ tùy cài đặt của giáo viên</li><li>Chọn đáp án / điền câu trả lời</li><li>Có thể <strong>đánh dấu câu</strong> chưa chắc để xem lại sau</li><li>Nhấn <strong>Câu tiếp</strong> hoặc điều hướng tự do giữa các câu</li></ul><h3 id="buoc-4-—-nop-bai" tabindex="-1">Bước 4 — Nộp bài <a class="header-anchor" href="#buoc-4-—-nop-bai" aria-label="Permalink to &quot;Bước 4 — Nộp bài&quot;">​</a></h3><ul><li>Nhấn <strong>Nộp bài</strong> khi đã hoàn thành</li><li>Hoặc hệ thống tự động nộp khi hết thời gian</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Khi đồng hồ về <strong>0</strong>, hệ thống tự nộp bài — kể cả những câu chưa trả lời. Hãy quản lý thời gian cẩn thận.</p></div><h2 id="xem-ket-qua" tabindex="-1">Xem kết quả <a class="header-anchor" href="#xem-ket-qua" aria-label="Permalink to &quot;Xem kết quả&quot;">​</a></h2><p>Sau khi nộp bài:</p><ol><li>Điểm số hiển thị ngay lập tức</li><li>Nhấn <strong>Xem đáp án</strong> để so sánh bài làm với đáp án đúng</li><li>Kết quả được lưu trong <strong>Kết quả học tập</strong> để theo dõi lâu dài</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Nếu điểm chưa cao, nhấn <strong>Xem lại bài</strong> để phân tích từng câu sai và hiểu nguyên nhân trước khi học tiếp.</p></div>',21)])])}con